mapper.select:
SELECT id, name, datasource_type, connect_mode, host, port, database_name, db_username, db_password, created_at
FROM bi_datasource
WHERE id = #{id}

mapper.update:
UPDATE bi_datasource
SET name = #{name}, datasource_type = #{datasourceType}, connect_mode = #{connectMode},
    host = #{host}, port = #{port},
    database_name = #{databaseName}, db_username = #{dbUsername}, db_password = #{dbPassword}
WHERE id = #{id}
